cat > "$tmp" <<'"'EOF'
package main

import (
    \"bytes\"
    \"fmt\"
    \"go/ast\"
    \"go/format\"
    \"go/parser\"
    \"go/token\"
    \"os\"
    \"path/filepath\"
    \"sort\"
    \"strings\"
)

func main() {
    root := \".\"
    var files []string
    err := filepath.Walk(filepath.Join(root, \"cli\"), func(path string, info os.FileInfo, err error) error {
        if err "'!= nil {
            return err
        }
        if info.IsDir() {
            return nil
        }
        if !strings.HasSuffix(path, ".go") {
            return nil
        }
        if strings.HasPrefix(filepath.ToSlash(path), "cli/internal/ddxroot/") {
            return nil
        }
        files = append(files, path)
        return nil
    })
    if err != nil {
        panic(err)
    }
    sort.Strings(files)

    modified := make([]string, 0)
    for _, path := range files {
        changed, err := rewriteFile(path)
        if err != nil {
            panic(fmt.Sprintf("%s: %v", path, err))
        }
        if changed {
            modified = append(modified, path)
        }
    }
    for _, path := range modified {
        fmt.Println(path)
    }
}

func rewriteFile(path string) (bool, error) {
    fset := token.NewFileSet()
    file, err := parser.ParseFile(fset, path, nil, parser.ParseComments)
    if err != nil {
        return false, err
    }

    isTest := strings.HasSuffix(path, "_test.go")
    changed := false

    ast.Inspect(file, func(n ast.Node) bool {
        call, ok := n.(*ast.CallExpr)
        if !ok || !isFilepathJoin(call) {
            return true
        }

        dotDDX := findDDXArgs(call.Args)
        if len(dotDDX) == 0 {
            return true
        }

        if isTest {
            for _, idx := range dotDDX {
                call.Args[idx] = ddxrootSelector("DirName")
            }
            changed = true
            return true
        }

        if len(dotDDX) != 1 {
            for _, idx := range dotDDX {
                call.Args[idx] = ddxrootSelector("DirName")
            }
            changed = true
            return true
        }

        idx := dotDDX[0]
        switch {
        case idx == 0:
            call.Fun = ddxrootSelector("JoinRelative")
            call.Args = append([]ast.Expr(nil), call.Args[1:]...)
            changed = true
        case idx == 1:
            base := call.Args[0]
            rest := append([]ast.Expr(nil), call.Args[2:]...)
            if isHomeLike(base) {
                call.Fun = ddxrootSelector("JoinHome")
            } else {
                call.Fun = ddxrootSelector("JoinProject")
            }
            call.Args = append([]ast.Expr{base}, rest...)
            changed = true
        default:
            call.Args[idx] = ddxrootSelector("DirName")
            changed = true
        }
        return true
    })

    if !changed {
        return false, nil
    }

    var buf bytes.Buffer
    if err := format.Node(&buf, fset, file); err != nil {
        return false, err
    }
    if err := os.WriteFile(path, buf.Bytes(), 0o644); err != nil {
        return false, err
    }
    return true, nil
}

func isFilepathJoin(call *ast.CallExpr) bool {
    sel, ok := call.Fun.(*ast.SelectorExpr)
    if !ok || sel.Sel == nil || sel.Sel.Name != "Join" {
        return false
    }
    ident, ok := sel.X.(*ast.Ident)
    return ok && ident.Name == "filepath"
}

func findDDXArgs(args []ast.Expr) []int {
    out := make([]int, 0, 1)
    for i, arg := range args {
        lit, ok := arg.(*ast.BasicLit)
        if !ok || lit.Kind != token.STRING || lit.Value != `".ddx"` {
            continue
        }
        out = append(out, i)
    }
    return out
}

func ddxrootSelector(name string) ast.Expr {
    return &ast.SelectorExpr{X: ast.NewIdent("ddxroot"), Sel: ast.NewIdent(name)}
}

func isHomeLike(expr ast.Expr) bool {
    var buf bytes.Buffer
    _ = format.Node(&buf, token.NewFileSet(), expr)
    return strings.Contains(strings.ToLower(buf.String()), "home")
}
