	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestPersistReviewerStream_WritesToBundle covers ddx-f8a11202 AC #2: a large
// reviewer stream persists to the attempt's execution bundle; the returned
// relative path is suitable for an event-body reference.
func TestPersistReviewerStream_WritesToBundle(t *testing.T) {
	projectRoot := t.TempDir()
	attemptID := "20260420T150000-abc123"
	beadID := "ddx-test-f8a11202"

	stream := strings.Repeat("S", 2*1024*1024) // 2MB reviewer stream

	rel, err := PersistReviewerStream(projectRoot, beadID, attemptID, stream)
	require.NoError(t, err)
	require.NotEmpty(t, rel)

	abs := filepath.Join(projectRoot, rel)
	data, err := os.ReadFile(abs)
	require.NoError(t, err)
	assert.Equal(t, len(stream), len(data), "full stream must land on disk verbatim; truncation here loses audit evidence")
	assert.Equal(t, filepath.Join(ddxroot.DirName, "executions", attemptID, "reviewer-stream.log"), rel,
		"artifact location must follow the .ddx/executions/<attempt>/ convention so existing tooling discovers it")
}

// TestPersistReviewerStream_FallbackWhenAttemptMissing covers the path where
// the review happens outside an execute-bead attempt (manual review, test
// invocations). The stream still persists — in a grouped reviewer-streams
// directory — so evidence is never dropped.
func TestPersistReviewerStream_FallbackWhenAttemptMissing(t *testing.T) {
	projectRoot := t.TempDir()

	rel, err := PersistReviewerStream(projectRoot, "ddx-test", "", "verdict text")
	require.NoError(t, err)
	require.NotEmpty(t, rel)
	assert.Contains(t, rel, filepath.Join(ddxroot.DirName, "executions", "reviewer-streams"),
		"fallback location must be discoverable via the same .ddx/executions/ root")
	abs := filepath.Join(projectRoot, rel)
	_, err = os.Stat(abs)
	require.NoError(t, err, "fallback must actually write the file, not just return a path")
}

// TestReviewEventBody_CapsAtMax covers AC #2: the event body for a reviewer
// verdict event must be at most 512 bytes regardless of reviewer rationale
// size. A 10KB rationale shall be summarized + artifact-referenced, not
// truncated in a way that loses the verdict or the path.
func TestReviewEventBody_CapsAtMax(t *testing.T) {
	rationale := strings.Repeat("A very long first line of rationale that must be truncated. ", 200)
	artifactPath := ".ddx/executions/20260420T150000-abc123/reviewer-stream.log"

	body := ReviewEventBody("APPROVE", rationale, artifactPath)

	assert.LessOrEqual(t, len(body), maxReviewerEventBody,
		"event body must never exceed the cap — downstream scanners and bd imports rely on per-field limits")
	assert.True(t, strings.HasPrefix(body, "APPROVE"),
		"verdict must be the first line so human readers see it without scrolling")
	assert.Contains(t, body, artifactPath,
		"artifact path must survive truncation — without it the reviewer stream is orphaned from its bead")
}

// TestReviewEventBody_EmptyRationaleStillCarriesVerdictAndArtifact covers the
// BLOCK-without-rationale malfunction path: even when the reviewer produced
// no usable rationale, the event must still link to the raw stream on disk so
// the operator can debug what happened.
func TestReviewEventBody_EmptyRationaleStillCarriesVerdictAndArtifact(t *testing.T) {
	artifactPath := ".ddx/executions/20260420T150000-abc123/reviewer-stream.log"

	body := ReviewEventBody("BLOCK without rationale", "", artifactPath)

	assert.Contains(t, body, "BLOCK without rationale")
	assert.Contains(t, body, artifactPath,
		"malfunction events must always reference the raw stream — this is the one case where forensics matter most")
}

// TestReviewEventBody_NoArtifactPath_StillFits covers the artifact-write-error
// fallback: if the sidecar write fails we still emit a body with verdict +
// short rationale, we just skip the artifact line. Body must still be bounded.
func TestReviewEventBody_NoArtifactPath_StillFits(t *testing.T) {
	rationale := strings.Repeat("x", 5000)
	body := ReviewEventBody("APPROVE", rationale, "")

	assert.LessOrEqual(t, len(body), maxReviewerEventBody)
	assert.True(t, strings.HasPrefix(body, "APPROVE"))
	assert.NotContains(t, body, "artifact:",
		"when no artifact was written, the body must not dangle a broken reference")
}

package agent

import (
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
)

// RunStateFileName is the basename of the live run-state file, relative to
// the project's .ddx directory.
const RunStateFileName = "run-state.json"

// RunStateDirName is the .ddx subdirectory containing per-attempt live-state
// records. The legacy .ddx/run-state.json file remains as a compatibility
// summary view for older operators.
const RunStateDirName = "run-state"

// RunStateLivenessTTL is the default expiry window written to refreshed
// attempt liveness records.
const RunStateLivenessTTL = 2 * time.Minute

// RunState is the on-disk record of an executing bead attempt. It is written at
// execute-bead start, refreshed while the agent runs, and removed on completion
// (or on orphan recovery of a crashed worker). Operators and HELIX consume this
// state to observe what is running without polling the bead tracker.
//
// See CONTRACT-001 §5 (Always-on runtime metrics and provenance).
type RunState struct {
	BeadID       string    `json:"bead_id"`
	AttemptID    string    `json:"attempt_id"`
	Harness      string    `json:"harness,omitempty"`
	Model        string    `json:"model,omitempty"`
	StartedAt    time.Time `json:"started_at"`
	WorktreePath string    `json:"worktree_path"`
	PID          int       `json:"pid,omitempty"`
	SessionID    string    `json:"session_id,omitempty"`
	RefreshedAt  time.Time `json:"refreshed_at,omitempty"`
	ExpiresAt    time.Time `json:"expires_at,omitempty"`
	// Candidate-cycle fields mirror cleanup metadata so operators can see
	// which candidate phase owns a long-lived attempt worktree.
	CandidateCyclePhase string `json:"candidate_cycle_phase,omitempty"`
	CandidateRef        string `json:"candidate_ref,omitempty"`
	CandidateRev        string `json:"candidate_rev,omitempty"`
	CycleIndex          int    `json:"cycle_index,omitempty"`
	ReviewActive        bool   `json:"review_active,omitempty"`
	RepairActive        bool   `json:"repair_active,omitempty"`
}

// runStatePath returns the absolute path of the run-state file for the
// project rooted at projectRoot.
func runStatePath(projectRoot string) string {
	return ddxroot.JoinProject(projectRoot, RunStateFileName)
}

func runStateDirPath(projectRoot string) string {
	return ddxroot.JoinProject(projectRoot, RunStateDirName)
}

func runStateAttemptPath(projectRoot, attemptID string) (string, error) {
	name, err := runStateAttemptFileName(attemptID)
	if err != nil {
		return "", err
	}
	return filepath.Join(runStateDirPath(projectRoot), name), nil
}

func runStateAttemptFileName(attemptID string) (string, error) {
	attemptID = strings.TrimSpace(attemptID)
	if attemptID == "" {
		return "", errors.New("run-state: attempt_id is empty")
	}
	if filepath.Base(attemptID) != attemptID || strings.ContainsAny(attemptID, `/\`) {
		return "", fmt.Errorf("run-state: invalid attempt_id %q", attemptID)
	}
	return attemptID + ".json", nil
}

func normalizeRunState(state RunState) RunState {
	now := time.Now().UTC()
	if state.StartedAt.IsZero() {
		state.StartedAt = now
	}
	if state.RefreshedAt.IsZero() {
		state.RefreshedAt = now
	}
	if state.ExpiresAt.IsZero() {
		state.ExpiresAt = state.RefreshedAt.Add(RunStateLivenessTTL)
	}
	if state.PID == 0 {
		state.PID = os.Getpid()
	}
	return state
}

// WriteRunState atomically writes state to a per-attempt file under
// .ddx/run-state/ and refreshes .ddx/run-state.json as a legacy compatibility
// summary. Writes go to sibling tmp files and are then renamed into place so
// readers never observe a partial record.
func WriteRunState(projectRoot string, state RunState) error {
	if projectRoot == "" {
		return errors.New("WriteRunState: projectRoot is empty")
	}
	state = normalizeRunState(state)
	attemptPath, err := runStateAttemptPath(projectRoot, state.AttemptID)
	if err != nil {
		return err
	}
	ddxDir := ddxroot.JoinProject(projectRoot)
	attemptDir := filepath.Dir(attemptPath)
	if err := os.MkdirAll(ddxDir, 0o755); err != nil {
		return fmt.Errorf("run-state: mkdir .ddx: %w", err)
	}
	if err := os.MkdirAll(attemptDir, 0o755); err != nil {
		return fmt.Errorf("run-state: mkdir attempts: %w", err)
	}
	if err := writeRunStateJSON(attemptPath, state); err != nil {
		return err
	}
	return writeRunStateJSON(runStatePath(projectRoot), state)
}

func writeRunStateJSON(final string, state RunState) error {
	dir := filepath.Dir(final)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("run-state: mkdir: %w", err)
	}
	data, err := json.MarshalIndent(state, "", "  ")
	if err != nil {
		return fmt.Errorf("run-state: marshal: %w", err)
	}
	data = append(data, '\n')

	tmp, err := os.CreateTemp(dir, "run-state-*.json.tmp")
	if err != nil {
		return fmt.Errorf("run-state: create tmp: %w", err)
	}
	tmpName := tmp.Name()
	if _, err := tmp.Write(data); err != nil {
		_ = tmp.Close()
		_ = os.Remove(tmpName)
		return fmt.Errorf("run-state: write tmp: %w", err)
	}
	if err := tmp.Close(); err != nil {
		_ = os.Remove(tmpName)
		return fmt.Errorf("run-state: close tmp: %w", err)
	}
	if err := os.Rename(tmpName, final); err != nil {
		_ = os.Remove(tmpName)
		return fmt.Errorf("run-state: rename: %w", err)
	}
	return nil
}

// ReadRunState returns a compatibility live-state summary for projectRoot, or
// (nil, nil) when no live attempt exists. A malformed compatibility file
// surfaces as an error; if the compatibility file is missing, the newest
// per-attempt record is returned.
func ReadRunState(projectRoot string) (*RunState, error) {
	state, err := readRunStateFile(runStatePath(projectRoot))
	if err != nil {
		if !os.IsNotExist(err) {
			return nil, err
		}
		states, statesErr := readRunStateAttemptFiles(projectRoot)
		if statesErr != nil {
			return nil, statesErr
		}
		if latest, ok := latestRunState(states); ok {
			return &latest, nil
		}
		return nil, nil
	}
	return state, nil
}

func readRunStateFile(path string) (*RunState, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, err
		}
		return nil, err
	}
	var s RunState
	if err := json.Unmarshal(data, &s); err != nil {
		return nil, fmt.Errorf("run-state: parse: %w", err)
	}
	return &s, nil
}

// ReadRunStates returns all live attempt records. The per-attempt directory is
// authoritative; when it is absent or empty, this falls back to the legacy
// compatibility file so older on-disk state can still be recovered.
func ReadRunStates(projectRoot string) ([]RunState, error) {
	states, err := readRunStateAttemptFiles(projectRoot)
	if err != nil {
		return nil, err
	}
	if len(states) > 0 {
		return states, nil
	}
	state, err := readRunStateFile(runStatePath(projectRoot))
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, err
	}
	if state == nil {
		return nil, nil
	}
	return []RunState{*state}, nil
}

